// 1. Sadə primitiv type alias
type Id = string | number;
let userId: Id = "U001";
console.log(userId); // Çıxış: U001
userId = 1001;
console.log(userId); // Çıxış: 1001
// userId = true; // Xəta: boolean Id tipinə uyğun deyil

// 2. Obyektlərdə type alias
type Point = { x: number; y: number };
const point: Point = { x: 10, y: 20 };
console.log(point); // Çıxış: { x: 10, y: 20 }

// 3. Literal tiplərlə type alias
type Status = "success" | "error" | "pending";
let status: Status = "success";
console.log(status); // Çıxış: success
// status = "failed"; // Xəta: failed Status tipinə uyğun deyil

// 4. Funksiyalarda type alias
type Greet = (name: string, greeting?: string) => string;
const sayHello: Greet = (name, greeting = "Hello") => `${greeting}, ${name}!`;
console.log(sayHello("Murad")); // Çıxış: Hello, Murad!
console.log(sayHello("Alice", "Hi")); // Çıxış: Hi, Alice!

// 5. Intersection types ilə type alias
type Person = { name: string; age: number };
type Role = { role: string };
type Employee = Person & Role;
const employee: Employee = {
  name: "Murad",
  age: 25,
  role: "Developer"
};
console.log(employee); // Çıxış: { name: "Murad", age: 25, role: "Developer" }

// 6. Generic type alias
type Box<T> = { value: T };
const numberBox: Box<number> = { value: 42 };
const stringBox: Box<string> = { value: "TypeScript" };
console.log(numberBox); // Çıxış: { value: 42 }
console.log(stringBox); // Çıxış: { value: "TypeScript" }

// Sadə mağaza sistemi
type Product = {
  id: string;
  name: string;
  price: number;
  inStock: boolean;
};

function displayProduct(product: Product): string {
  return `${product.name} (ID: ${product.id}): $${product.price}, ${product.inStock ? "mövcuddur" : "mövcud deyil"}`;
}

const laptop: Product = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true
};
console.log(displayProduct(laptop)); // Çıxış: Laptop (ID: P001): $1200, mövcuddur

// Generic type alias ilə sifariş qutusu
type OrderBox<T> = {
  orderId: string;
  content: T;
};
const order: OrderBox<Product> = {
  orderId: "O001",
  content: laptop
};
console.log(order); // Çıxış: { orderId: "O001", content: { id: "P001", name: "Laptop", price: 1200, inStock: true } }

