console.log(point); // Output: { x: 10, y: 20 }

// 3. Literal types with type alias
type Status = "success" | "error" | "pending";
let status: Status = "success";
console.log(status); // Output: success
// status = "failed"; // Error: failed is not Status type

// 4. Function type alias
type Greet = (name: string, greeting?: string) => string;
const sayHello: Greet = (name, greeting = "Hello") => `${greeting}, ${name}!`;
console.log(sayHello("Murad")); // Output: Hello, Murad!
console.log(sayHello("Alice", "Hi")); // Output: Hi, Alice!

// 5. Intersection types with type alias
type Person = { name: string; age: number };
type Role = { role: string };
type Employee = Person & Role;
const employee: Employee = {
  name: "Murad",
  age: 25,
  role: "Developer"
};
console.log(employee); // Output: { name: "Murad", age: 25, role: "Developer" }

// 6. Generic type alias
type Box<T> = { value: T };
const numberBox: Box<number> = { value: 42 };
const stringBox: Box<string> = { value: "TypeScript" };
console.log(numberBox); // Output: { value: 42 }
console.log(stringBox); // Output: { value: "TypeScript" }

// Simple store system
type Product = {
  id: string;
  name: string;
  price: number;
  inStock: boolean;
};

function displayProduct(product: Product): string {
  return `${product.name} (ID: ${product.id}): $${product.price}, ${product.inStock ? "in stock" : "out of stock"}`;
}

const laptop: Product = {
  id: "P001",
  name: "Laptop",
  price: 1200,
  inStock: true
};
console.log(displayProduct(laptop)); // Output: Laptop (ID: P001): $1200, in stock

// Generic type alias for order box
type OrderBox<T> = {
  orderId: string;
  content: T;
};
const order: OrderBox<Product> = {
  orderId: "O001",
  content: laptop
};
console.log(order); // Output: { orderId: "O001", content: { id: "P001", name: "Laptop", price: 1200, inStock: true } }

